use std::ops::Deref;

use crypto_bigint::{
    NonZero, Uint, const_monty_params,
    modular::{ConstMontyForm, ConstMontyParams},
};

/// A multiplicative cyclic group is defined modulo p (as defined in the MOD type).
/// The generator g generates a cyclic group of prime order q.
///
/// There are no checks in place for this (because actually computing it would be infeasible),
/// but for security these groups should only be defined for prime p and q
/// (i.e. q is a Sophie-Germain prime, and p is a safe prime).
pub trait MCG<const LIMBS: usize>: Deref<Target = ConstMontyForm<Self::MOD, LIMBS>> {
    type MOD: ConstMontyParams<LIMBS>;

    fn q() -> NonZero<Uint<LIMBS>>
    where
        Self: Sized;
    fn g() -> ConstMontyForm<Self::MOD, LIMBS>
    where
        Self: Sized;

    fn p() -> Uint<LIMBS>
    where
        Self: Sized,
    {
        **Self::MOD::PARAMS.modulus()
    }

    fn into_inner(self) -> ConstMontyForm<Self::MOD, LIMBS>;

    fn contains(n: ConstMontyForm<Self::MOD, LIMBS>) -> bool;

    /// Takes some integer modulo p and checks that it is in the group generated by g (which has order q).
    /// If it is, yields an instance of the group type.
    fn from_modp(n: ConstMontyForm<Self::MOD, LIMBS>) -> Option<Self>
    where
        Self: Sized;

    /// Converts some integer in \[0, q) to it's corresponding integer that is a member of G.
    /// This allows us to map Z_q (kind of) to G, which makes encoding messages a lot easier,
    /// since now the message space can be treated as Z_q instead of G (which has lots of gaps).
    ///
    /// This works by exploiting the fact that since p = 2 * q + 1 and both p and q are prime,
    /// the quadratic residue modulo p are exactly the members of G.
    /// We therefore map integers that are quadratic residue modulo p to themselves,
    /// and integers that are not to their negation (which is guaranteed to be both > q and in G).
    ///
    /// Returns None if n is not an integer modq.
    fn from_modq(n: Uint<LIMBS>) -> Option<Self>
    where
        Self: Sized;

    /// Reverse operation of [from_modq]
    fn to_modq(&self) -> Uint<LIMBS>
    where
        Self: Sized;
}

#[macro_export]
macro_rules! new_group {
    ($name:ident, $mod_name:ident, $limbs:expr, $p:expr, $q:expr, $g:expr $(,)?) => {
        #[derive(Debug, Clone, Copy, PartialEq, Eq)]
        pub struct $name(ConstMontyForm<$mod_name, $limbs>);

        const_monty_params!($mod_name, Uint<$limbs>, $p);

        impl MCG<$limbs> for $name {
            type MOD = $mod_name;

            fn q() -> NonZero<Uint<$limbs>> {
                NonZero::from_be_hex($q)
            }

            fn g() -> ConstMontyForm<Self::MOD, $limbs> {
                ConstMontyForm::new(&Uint::from_u64($g))
            }

            fn into_inner(self) -> ConstMontyForm<Self::MOD, $limbs> {
                let Self(inner) = self;
                inner
            }

            fn contains(n: ConstMontyForm<Self::MOD, $limbs>) -> bool {
                n.pow(&Self::q()) == ConstMontyForm::ONE
            }

            fn from_modp(n: ConstMontyForm<Self::MOD, $limbs>) -> Option<Self> {
                if Self::contains(n) {
                    Some(Self(n))
                } else {
                    None
                }
            }

            fn from_modq(mut n: Uint<$limbs>) -> Option<Self> {
                if n >= *Self::q() {
                    return None;
                }

                // Technically encoding 0 using this process doesn't work,
                // so we just map 0 -> q.
                if n == Uint::ZERO {
                    n = *Self::q();
                }

                let n = ConstMontyForm::new(&n);

                if Self::contains(n) {
                    // If we're already in G, no need to map
                    Some(Self(n))
                } else {
                    let neg = n.neg();
                    debug_assert!(
                        Self::contains(neg),
                        "Something has gone wrong. Failed to lift {} into group.",
                        n.retrieve()
                    );

                    Some(Self(neg))
                }
            }

            fn to_modq(&self) -> Uint<$limbs> {
                let inner = self.into_inner();
                if inner.retrieve() == *Self::q() {
                    return Uint::ZERO;
                } else if inner.retrieve() < *Self::q() {
                    inner.retrieve()
                } else {
                    inner.neg().retrieve()
                }
            }
        }

        impl std::ops::Deref for $name {
            type Target = ConstMontyForm<$mod_name, $limbs>;

            fn deref(&self) -> &Self::Target {
                let $name(inner) = self;
                inner
            }
        }
    };
}

new_group!(
    GroupTiny,
    ModPTiny,
    1,
    "0000000000000017",
    "000000000000000B",
    2
);

new_group!(
    GroupSmall,
    ModPSmall,
    1,
    "00000000000000A7", // 167
    "0000000000000053", // 83
    2
);

new_group!(
    Group2048,
    ModP2048,
    32,
    "",
    "",
    2
);

new_group!(
    Group3072,
    ModP3072,
    48,
    "",
    "",
    2
);

new_group!(
    Group4096,
    ModP4096,
    64,
    "",
    "",
    2
);

#[cfg(test)]
mod tests {
    use crypto_bigint::U64;

    use crate::groups::{GroupSmall, GroupTiny, MCG};

    #[test]
    fn test_into_group_tiny() {
        let mut results = vec![];

        let mut i = U64::ZERO;
        while i < *GroupTiny::q() {
            let g = GroupTiny::from_modq(i).unwrap();
            assert!(!results.contains(&g));
            results.push(g);
            i += U64::ONE;
        }
    }

    #[test]
    fn test_into_group_small() {
        let mut results = vec![];

        let mut i = U64::ZERO;
        while i < *GroupSmall::q() {
            let g = GroupSmall::from_modq(i).unwrap();
            assert!(!results.contains(&g), "{} already seen!", g.retrieve());
            results.push(g);
            i += U64::ONE;
        }
    }
}
